#include<bits/stdc++.h>
#define rep(a,b,c) for(register int c=(a);c<=(b);++c)
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
const int N=2010;const double INF=1e10;
struct Sort{int x,dlt;inline bool operator<(const Sort &g)const{return x<g.x;}}Q[N];
double dp[2][N][N];int t[N],s[N];
inline void Solve(int n,int spd,int S)
{
	memset(s,0,sizeof(s));memset(t,0,sizeof(t));
	rep(1,n+1,i)Q[i].x=Q[i].dlt=0;
	rep(1,n+1,i)rep(1,n+1,j)dp[0][i][j]=dp[1][i][j]=INF;
	bool flag=0;double ans=0;rep(1,n,i){Q[i].x=read();ans+=read();Q[i].dlt=read();flag|=(Q[i].x==S);}
	if(!flag)Q[++n].x=S,Q[n].dlt=0;sort(Q+1,Q+n+1);rep(1,n,i)s[i]=s[i-1]+Q[i].dlt,t[i]=Q[i].x;
	rep(1,n,i)if(t[i]==S){S=i;break;}
	dp[0][S][S]=dp[1][S][S]=0.0;rep(2,n,len)
	{
		for(int l=1,r=len;r<=n;++l,++r)
		{
			dp[0][l][r]=min(dp[0][l+1][r]+(1.0*(t[l+1]-t[l])/spd)*(s[n]-(s[r]-s[l])),
							dp[1][l+1][r]+(1.0*(t[r]-t[l])/spd)*(s[n]-(s[r]-s[l])));
			dp[1][l][r]=min(dp[1][l][r-1]+(1.0*(t[r]-t[r-1])/spd)*(s[n]-(s[r-1]-s[l-1])),
							dp[0][l][r-1]+(1.0*(t[r]-t[l])/spd)*(s[n]-(s[r-1]-s[l-1])));
		}
	}
	printf("%d\n",int(floor(1.0*ans+min(dp[0][1][n],dp[1][1][n]))));
}
int main()
{
	int n,spd,S;while(cin>>n){spd=read();S=read();if(n==0)break;Solve(n,spd,S);}
	return 0;
}
